import { writeOutput } from "./codegen";

const DOCS_URL = "https://developer.adzuna.com/overview";
const APP_KEY_PLACEHOLDER = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Adzuna API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:adzuna",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const adzunaFirewall = {",
    '  name: "adzuna",',
    '  description: "Adzuna Jobs API",',
    "  placeholders: {",
    `    ADZUNA_APP_KEY: "${APP_KEY_PLACEHOLDER}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.adzuna.com",',
    "      auth: {",
    "        query: {",
    '          app_id: "${{ vars.ADZUNA_APP_ID }}",',
    '          app_key: "${{ secrets.ADZUNA_APP_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Adzuna firewall config...");
  const ts = generateTypeScript();
  writeOutput("adzuna", ts, import.meta.dirname);
}
